// Go benchmarks for the tabnas engine via the json (strict) and jsonic
// (relaxed) grammars, against an encoding/json baseline.
//
// Fixtures are generated by ../genfixture.js into the directory named by
// BENCH_FIXTURE_DIR (run via ../run-bench.sh, which sets it). Run:
//
//	go test -bench=. -benchmem -run='^$' -benchtime=2s
package tabnasbench

import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"

	tabnasjson "github.com/tabnas/json/go"
	jsonic "github.com/tabnas/jsonic/go"
)

func fixture(b *testing.B, name string) string {
	dir := os.Getenv("BENCH_FIXTURE_DIR")
	if dir == "" {
		b.Skip("BENCH_FIXTURE_DIR not set (run via ci/bench/run-bench.sh)")
	}
	data, err := os.ReadFile(filepath.Join(dir, name))
	if err != nil {
		b.Fatal(err)
	}
	return string(data)
}

func benchTabnasJson(b *testing.B, src string) {
	j := tabnasjson.Make()
	if _, err := j.Parse(src); err != nil {
		b.Fatal(err)
	}
	b.ReportAllocs()
	b.SetBytes(int64(len(src)))
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		if _, err := j.Parse(src); err != nil {
			b.Fatal(err)
		}
	}
}

func benchJsonic(b *testing.B, src string) {
	j := jsonic.Make(jsonic.Options{})
	if _, err := j.Parse(src); err != nil {
		b.Fatal(err)
	}
	b.ReportAllocs()
	b.SetBytes(int64(len(src)))
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		if _, err := j.Parse(src); err != nil {
			b.Fatal(err)
		}
	}
}

func BenchmarkJsonRecords1MB(b *testing.B)  { benchTabnasJson(b, fixture(b, "records-1mb.json")) }
func BenchmarkJsonEscaped1MB(b *testing.B)  { benchTabnasJson(b, fixture(b, "records-escaped-1mb.json")) }
func BenchmarkJsonNumbers1MB(b *testing.B)  { benchTabnasJson(b, fixture(b, "numbers-1mb.json")) }
func BenchmarkJsonRecords16KB(b *testing.B) { benchTabnasJson(b, fixture(b, "records-16kb.json")) }
func BenchmarkJsonNested(b *testing.B)      { benchTabnasJson(b, fixture(b, "nested-256.json")) }

func BenchmarkJsonTiny(b *testing.B) { benchTabnasJson(b, `{"a":1,"b":[true,null,2.5],"c":"x"}`) }
func BenchmarkJsonPadded(b *testing.B) {
	benchJsonic(b, `{"a":1}`+strings.Repeat(" ", 10000))
}

func BenchmarkJsonicRecords1MB(b *testing.B) { benchJsonic(b, fixture(b, "records-1mb.json")) }
func BenchmarkJsonicText1MB(b *testing.B)    { benchJsonic(b, fixture(b, "text-1mb.jsonic")) }

func BenchmarkStdlibRecords1MB(b *testing.B) {
	src := []byte(fixture(b, "records-1mb.json"))
	b.ReportAllocs()
	b.SetBytes(int64(len(src)))
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		var v any
		if err := json.Unmarshal(src, &v); err != nil {
			b.Fatal(err)
		}
	}
}
